(function(){'use strict';
function waitForDomReady(){return new Promise(function(r){if(document.readyState==="complete")return r();window.addEventListener("load",function(){r()},{once:true})})}
function getOrCreatePrintContainer(id){id=id||"print-content";var c=document.getElementById(id);if(c)return c;c=document.createElement("div");c.id=id;c.style.display="none";document.body.appendChild(c);return c}
function injectContentToPrint(c,content){c.appendChild(content)}
function waitForRender(t){return new Promise(function(r){setTimeout(r,t||50)})}
function cleanupAfterPrint(c){setTimeout(function(){c.innerHTML=""},500)}
function printPage(){window.print()}
function getElementByIdSafe(id){if(!id)return null;var el=document.getElementById(id);if(!el){console.error("easy-print-js: Element not found:",id);return null}return el}
function createBaseTable(){var t=document.createElement("table");t.id="easy-print-table";t.style.borderCollapse="collapse";t.style.inlineSize="100%";t.style.breakInside="auto";return t}
function createSectionForBaseTable(table,tag,content){var s=document.createElement(tag);var tr=document.createElement("tr");var th=document.createElement("th");th.appendChild(content.cloneNode(true));tr.appendChild(th);s.appendChild(tr);table.appendChild(s)}
function buildPrintStructure(opt){var headerEl=getElementByIdSafe(opt.headerElementId);var contentEl=getElementByIdSafe(opt.contentElementId);var footerEl=getElementByIdSafe(opt.footerElementId);var table=createBaseTable();if(headerEl)createSectionForBaseTable(table,"thead",headerEl);if(contentEl)createSectionForBaseTable(table,"tbody",contentEl);if(footerEl)createSectionForBaseTable(table,"tfoot",footerEl);return table}
function injectPrintStyles(){var id="easy-print-js-style";if(document.getElementById(id))return;var s=document.createElement("style");s.id=id;s.textContent="@media print{@page{margin:0;size:auto}html,body{position:static!important;padding:0!important;margin:0!important;block-size:100%!important}*{-webkit-print-color-adjust:exact!important;print-color-adjust:exact!important}#print-content{display:block!important}body>*:not(#print-content){display:none!important}}";document.head.appendChild(s)}
function easyPrint(opt){return Promise.resolve().then(function(){return waitForDomReady()}).then(function(){var html=buildPrintStructure(opt||{});var pc=getOrCreatePrintContainer();injectContentToPrint(pc,html);injectPrintStyles();return waitForRender()}).then(function(){printPage();var pc=getOrCreatePrintContainer();cleanupAfterPrint(pc)})}
window.easyPrint=easyPrint;
})();
